"""Immutable registry for every PNG generated by BroEdenBot.

The dashboard and renderer integration both consume these definitions. Upload
recommendations must never be duplicated in templates or JavaScript.
"""

from __future__ import annotations

from dataclasses import asdict, dataclass, field
from fractions import Fraction
from typing import Any, Dict, Iterable, Mapping, Optional, Tuple


SUPPORTED_IMAGE_FORMATS = ("PNG", "JPEG", "WEBP")
MAX_UPLOAD_BYTES = 10_000_000


@dataclass(frozen=True)
class SafeArea:
    top: int
    right: int
    bottom: int
    left: int
    obscured_regions: Tuple[Tuple[int, int, int, int, str], ...] = ()


@dataclass(frozen=True)
class AssetSlot:
    key: str
    label: str
    asset_type: str
    recommended_width: int
    recommended_height: int
    minimum_width: int
    minimum_height: int
    maximum_width: int
    maximum_height: int
    maximum_bytes: int = MAX_UPLOAD_BYTES
    formats: Tuple[str, ...] = SUPPORTED_IMAGE_FORMATS
    transparency: str = "supported"
    fit: str = "cover"
    safe_area: SafeArea = field(default_factory=lambda: SafeArea(0, 0, 0, 0))
    description: str = ""

    @property
    def aspect_ratio(self) -> str:
        fraction = Fraction(
            self.recommended_width, self.recommended_height
        ).limit_denominator(512)
        return "{}:{}".format(fraction.numerator, fraction.denominator)

    def as_dict(self) -> Dict[str, Any]:
        value = asdict(self)
        value["aspect_ratio"] = self.aspect_ratio
        value["formats"] = list(self.formats)
        value["safe_area"]["obscured_regions"] = [
            {
                "x": region[0],
                "y": region[1],
                "width": region[2],
                "height": region[3],
                "label": region[4],
            }
            for region in self.safe_area.obscured_regions
        ]
        return value


@dataclass(frozen=True)
class TemplateDefinition:
    key: str
    display_name: str
    description: str
    category: str
    renderer: str
    width: int
    height: int
    supported_settings: Tuple[str, ...]
    asset_slots: Tuple[AssetSlot, ...]
    defaults: Mapping[str, Any]
    command_source: str
    maximum_items: int = 0
    output_format: str = "PNG"
    max_output_bytes: int = 8_000_000
    legacy_fallback: str = ""

    @property
    def aspect_ratio(self) -> str:
        fraction = Fraction(self.width, self.height).limit_denominator(512)
        return "{}:{}".format(fraction.numerator, fraction.denominator)

    def slot(self, key: str) -> AssetSlot:
        for slot in self.asset_slots:
            if slot.key == key:
                return slot
        raise KeyError("Unknown asset slot {!r} for {}".format(key, self.key))

    def as_dict(self) -> Dict[str, Any]:
        return {
            "template_key": self.key,
            "display_name": self.display_name,
            "description": self.description,
            "category": self.category,
            "renderer": self.renderer,
            "canvas": {"width": self.width, "height": self.height},
            "aspect_ratio": self.aspect_ratio,
            "output": {
                "format": self.output_format,
                "max_file_size_bytes": self.max_output_bytes,
            },
            "supported_settings": list(self.supported_settings),
            "asset_slots": [slot.as_dict() for slot in self.asset_slots],
            "defaults": dict(self.defaults),
            "command_source": self.command_source,
            "maximum_items": self.maximum_items,
            "legacy_fallback": self.legacy_fallback,
        }


class TemplateRegistry:
    def __init__(self, templates: Iterable[TemplateDefinition] = ()) -> None:
        self._templates: Dict[str, TemplateDefinition] = {}
        for template in templates:
            self.register(template)

    def register(self, template: TemplateDefinition) -> None:
        if not template.key or not template.key.replace("_", "").isalnum():
            raise ValueError("Template keys must contain letters, digits, and underscores.")
        if template.key in self._templates:
            raise ValueError("Duplicate visual template key: {}".format(template.key))
        if template.width <= 0 or template.height <= 0:
            raise ValueError("Template canvas dimensions must be positive.")
        slot_keys = [slot.key for slot in template.asset_slots]
        if len(slot_keys) != len(set(slot_keys)):
            raise ValueError("Duplicate asset slot in {}".format(template.key))
        self._templates[template.key] = template

    def get(self, key: str) -> TemplateDefinition:
        try:
            return self._templates[key]
        except KeyError:
            raise KeyError("Unknown visual template: {}".format(key))

    def all(self) -> Tuple[TemplateDefinition, ...]:
        return tuple(
            sorted(
                self._templates.values(),
                key=lambda item: (item.category, item.display_name.casefold()),
            )
        )

    def as_dicts(self) -> Tuple[Dict[str, Any], ...]:
        return tuple(template.as_dict() for template in self.all())


