def _background_slot(width: int, height: int, safe: SafeArea) -> AssetSlot:
    return AssetSlot(
        key="background",
        label="Full-canvas background",
        asset_type="background",
        recommended_width=width,
        recommended_height=height,
        minimum_width=max(1, int(width * 0.8)),
        minimum_height=max(1, int(height * 0.8)),
        maximum_width=width * 3,
        maximum_height=height * 3,
        safe_area=safe,
        fit="cover",
        description="The normalized copy is cropped to cover the full canvas.",
    )


