def _ranked(
    key: str,
    name: str,
    description: str,
    category: str,
    command: str,
    legacy: str = "",
) -> TemplateDefinition:
    defaults = dict(DEFAULTS)
    defaults["maximum_rows"] = 10
    return TemplateDefinition(
        key=key,
        display_name=name,
        description=description,
        category=category,
        renderer="utils.stats_visuals.render_ranked_graphic_result",
        width=1200,
        height=1500,
        supported_settings=RANKED_SETTINGS,
        asset_slots=(
            _background_slot(1200, 1500, PORTRAIT_SAFE),
            HEADER_SLOT,
            LOGO_SLOT,
            WATERMARK_SLOT,
        ),
        defaults=defaults,
        command_source=command,
        maximum_items=10,
        legacy_fallback=legacy,
    )


