def asset_type_guidance(asset_type: str) -> Dict[str, Any]:
    """Return generic guidance when an asset is not tied to a template slot."""
    definitions = {
        "logo": (1024, 1024, 256, 256, 2048, 2048, "1:1", "required"),
        "watermark": (1200, 300, 600, 150, 2400, 600, "4:1", "required"),
        "header_graphic": (1104, 208, 552, 104, 3312, 624, "69:13", "supported"),
        "overlay": (1600, 900, 320, 180, 4800, 2700, "varies", "required"),
        "avatar_frame": (512, 512, 256, 256, 1024, 1024, "1:1", "required"),
        "badge": (256, 256, 64, 64, 1024, 1024, "1:1", "required"),
        "icon": (256, 256, 64, 64, 1024, 1024, "1:1", "required"),
    }
    values = definitions.get(asset_type, (1600, 900, 320, 180, 4800, 2700, "varies", "supported"))
    return {
        "recommended_width": values[0],
        "recommended_height": values[1],
        "minimum_width": values[2],
        "minimum_height": values[3],
        "maximum_width": values[4],
        "maximum_height": values[5],
        "aspect_ratio": values[6],
        "transparency": values[7],
        "maximum_bytes": MAX_UPLOAD_BYTES,
        "formats": list(
            ("PNG", "WEBP") if values[7] == "required" else SUPPORTED_IMAGE_FORMATS
        ),
    }
